'use strict';

// MAIN //

/**
* Fills a double-precision floating-point strided array with linearly spaced numeric elements which increment by `1` starting from a specified value.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {number} start - starting value
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {Float64Array} input array
*
* @example
* import Float64Array from '@stdlib/array-float64';
*
* var x = new Float64Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* dunitspace( x.length, 3.0, x, 1, 0 );
* // x => <Float64Array>[ 3.0, 4.0, 5.0, 6.0 ]
*/
function dunitspace( N, start, x, strideX, offsetX ) {
	var ix;
	var i;

	if ( N <= 0 ) {
		return x;
	}
	ix = offsetX;
	for ( i = 0; i < N; i++ ) {
		x[ ix ] = start + i;
		ix += strideX;
	}
	return x;
}


// EXPORTS //

export default dunitspace;
